import jwt
from Crypto.PublicKey import RSA
from jwt.algorithms import RSAController

def decode_and_verify_jwt(token, public_key):
    algorithem = RSAController(RSA.importKey(public_key))
    try:
        payload = jwt.decode(token, algorithem, audience='your_audience', issuer='your_issuer')
        return payload
    except jwt.ExpiredSignatureError as e:
        print("Token is expired.")
    except jwt.InvalidTokenError as e:
        print("Invalid token.")